import React, { useState } from "react";

import Sidebar from "./components/Sidebar";

import Dashboard from "./pages/Dashboard";
import Weather from "./pages/Weather";
import CropAdvisor from "./pages/CropAdvisor";
import Marketplace from "./pages/Marketplace";
import GovernmentSchemes from "./pages/GovernmentSchemes";
import News from "./pages/News";
import Maps from "./pages/Maps";
import Reports from "./pages/Reports";
import Tasks from "./pages/Tasks";
import Finance from "./pages/Finance";
import FarmRecords from "./pages/FarmRecords";
import Inventory from "./pages/Inventory";
import Complaint from "./pages/Complaint";
import Calendar from "./pages/Calendar";
import Profile from "./pages/Profile";
import Settings from "./pages/Settings";
import HelpSupport from "./pages/HelpSupport";

function App() {

const [activePage,setActivePage]=useState("Dashboard");

return(

<div className="app">

<Sidebar

activePage={activePage}

setActivePage={setActivePage}

/>

<div className="main-content">

{activePage==="Dashboard" && <Dashboard setActivePage={setActivePage}/>}

{activePage==="Weather" && <Weather/>}

{activePage==="Crop Advisor" && <CropAdvisor/>}

{activePage==="Marketplace" && <Marketplace/>}

{activePage==="Government Schemes" && <GovernmentSchemes/>}

{activePage==="News" && <News/>}

{activePage==="Maps" && <Maps/>}

{activePage==="Reports" && <Reports/>}

{activePage==="Tasks" && <Tasks/>}

{activePage==="Finance" && <Finance/>}

{activePage==="Farm Records" && <FarmRecords/>}

{activePage==="Inventory" && <Inventory/>}

{activePage==="Complaints" && <Complaint/>}

{activePage==="Calendar" && <Calendar/>}

{activePage==="Profile" && <Profile/>}

{activePage==="Settings" && <Settings/>}

{activePage==="HelpSupport" && <HelpSupport/>}

</div>

</div>

);

}

export default App;
